def generate_and_score_candidate(query: str, doc_text: str) -> Candidate:
    # Generate answer from this doc
    answer = llm.invoke(
        f"Answer the question using ONLY this document.\nDocument: {doc_text}\nQuestion: {query}"
    ).content.strip()

    # [IsSup]: is the answer grounded?
    sup_prompt = (
        f"Is every claim in the answer directly supported by the document?\n"
        f"Document: {doc_text[:400]}\nAnswer: {answer}\n"
        "Reply: fully_supported / partially_supported / not_supported"
    )
    sup_raw = llm.invoke(sup_prompt).content.strip().lower()
    if "fully" in sup_raw:
        supported = SupportDecision.FULLY
    elif "partial" in sup_raw:
        supported = SupportDecision.PARTIAL
    else:
        supported = SupportDecision.NOT

    # [IsUse]: how useful is the answer?
    use_prompt = f"Rate how useful this answer is for the question (1=not useful, 5=very useful).\nQuestion: {query}\nAnswer: {answer}\nReturn only a number 1-5:"
    try:
        usefulness = int(llm.invoke(use_prompt).content.strip()[0])
    except (ValueError, IndexError):
        usefulness = 3

    return Candidate(text=answer, is_supported=supported, usefulness=usefulness)

def self_rag(query: str, retriever) -> str:
    # [Retrieve] token
    if retrieve_token(query) == RetrieveDecision.NO:
        return llm.invoke(query).content

    docs = retriever.invoke(query)
    candidates = []

    for doc in docs:
        # [IsRel] token
        if isrel_token(query, doc.page_content) == RelevanceDecision.IRRELEVANT:
            continue
        candidate = generate_and_score_candidate(query, doc.page_content)
        candidates.append(candidate)

    if not candidates:
        return llm.invoke(query).content  # fallback

    # Score: prefer fully supported, then highest usefulness
    def score(c: Candidate) -> tuple:
        sup_score = {SupportDecision.FULLY: 2, SupportDecision.PARTIAL: 1, SupportDecision.NOT: 0}[c.is_supported]
        return (sup_score, c.usefulness)

    best = max(candidates, key=score)
    return best.text

from langgraph.graph import StateGraph, END
from typing import TypedDict, Literal

class SelfRAGState(TypedDict):
    question: str
    docs: list
    candidates: list
    answer: str

def retrieve_node(state: SelfRAGState) -> SelfRAGState:
    if retrieve_token(state["question"]) == RetrieveDecision.NO:
        direct = llm.invoke(state["question"]).content
        return {**state, "answer": direct}
    docs = retriever.invoke(state["question"])
    return {**state, "docs": docs}

def grade_and_generate_node(state: SelfRAGState) -> SelfRAGState:
    candidates = []
    for doc in state["docs"]:
        if isrel_token(state["question"], doc.page_content) == RelevanceDecision.IRRELEVANT:
            continue
        c = generate_and_score_candidate(state["question"], doc.page_content)
        candidates.append(c)
    return {**state, "candidates": candidates}

def select_best_node(state: SelfRAGState) -> SelfRAGState:
    if not state["candidates"]:
        return {**state, "answer": llm.invoke(state["question"]).content}
    best = max(state["candidates"], key=lambda c: ({SupportDecision.FULLY: 2, SupportDecision.PARTIAL: 1, SupportDecision.NOT: 0}[c.is_supported], c.usefulness))
    return {**state, "answer": best.text}

def route_after_retrieve(state: SelfRAGState) -> Literal["grade", "done"]:
    return "done" if state.get("answer") else "grade"

g = StateGraph(SelfRAGState)
g.add_node("retrieve", retrieve_node)
g.add_node("grade", grade_and_generate_node)
g.add_node("select", select_best_node)
g.set_entry_point("retrieve")
g.add_conditional_edges("retrieve", route_after_retrieve, {"grade": "grade", "done": END})
g.add_edge("grade", "select")
g.add_edge("select", END)
app = g.compile()

from dataclasses import dataclass, field
from typing import List


@dataclass
class SelfRAGMetrics:
    retrieval_decisions: List[bool] = field(default_factory=list)
    isrel_scores: List[bool] = field(default_factory=list)
    issup_scores: List[bool] = field(default_factory=list)
    isuse_scores: List[bool] = field(default_factory=list)

    def log(self, retrieved: bool, is_rel: bool, is_sup: bool, is_use: bool):
        self.retrieval_decisions.append(retrieved)
        if retrieved:
            self.isrel_scores.append(is_rel)
            self.issup_scores.append(is_sup)
            self.isuse_scores.append(is_use)

    def report(self) -> dict:
        def pct(lst):
            return round(sum(lst) / len(lst) * 100, 1) if lst else 0.0
        return {
            "retrieve_rate": pct(self.retrieval_decisions),
            "retrieval_precision": pct(self.isrel_scores),
            "support_rate": pct(self.issup_scores),
            "utility_rate": pct(self.isuse_scores),
        }


metrics = SelfRAGMetrics()
metrics.log(retrieved=True, is_rel=True, is_sup=True, is_use=True)
metrics.log(retrieved=True, is_rel=False, is_sup=False, is_use=False)
metrics.log(retrieved=False, is_rel=False, is_sup=False, is_use=False)
print(metrics.report())
